parameters.functionCode:
const body = $input.item.json.body;

if (!body.system || !body.action) {
  throw new Error('Missing required fields: system, action');
}

let mqttTopic = '';
let mqttMessage = {};

switch(body.system) {
  case 'irrigation':
    mqttTopic = 'greenhouse/control/irrigation';
    mqttMessage = {
      action: body.action,
      zone: body.zone,
      duration: body.duration || 60000
    };
    break;

  case 'climate':
    mqttTopic = 'greenhouse/control/climate';
    mqttMessage = {
      action: body.action,
      temperature: body.temperature,
      state: body.state
    };
    break;

  case 'ventilation':
    mqttTopic = 'greenhouse/control/ventilation';
    mqttMessage = {
      action: body.action,
      speed: body.speed,
      angle: body.angle
    };
    break;

  default:
    throw new Error('Unknown system: ' + body.system);
}

return {
  json: {
    topic: mqttTopic,
    message: mqttMessage,
    originalRequest: body,
    timestamp: new Date()
  }
};

